import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import type { ISudokuInstruction } from './types'
import { SudokuInstructionType } from './types'

export function runInstructs(
  attempt: ISudokuBoard,
  instructions: ReadonlyArray<ISudokuInstruction>,
): void {
  for (const instruction of instructions) {
    switch (instruction.type) {
      case SudokuInstructionType.ERASE: {
        const { r, c } = instruction.payload
        // eslint-disable-next-line no-param-reassign
        attempt[r][c] = -1
        break
      }
      case SudokuInstructionType.WRITE: {
        const { r, c, v } = instruction.payload
        // eslint-disable-next-line no-param-reassign
        attempt[r][c] = v
        break
      }
      default:
    }
  }
}
